spec:
// Container build/runtime contract for deployment tasks
// Files: Dockerfile, nginx/nginx.conf

// Build stage
FROM node:20-alpine AS builder
WORKDIR /app
COPY package.json package-lock.json ./
RUN npm ci
COPY . .
ENV/ARG: SUPABASE_URL, SUPABASE_ANON_KEY, GOOGLE_IOS_REVERSED_CLIENT_ID, EAS_PROJECT_ID
RUN npm run build:web
// Output written to /app/dist

// Runtime stage
FROM nginx:alpine
COPY nginx/nginx.conf /etc/nginx/nginx.conf
COPY --from=builder /app/dist /usr/share/nginx/html
EXPOSE 80
CMD ["nginx", "-g", "daemon off;"]

// nginx/nginx.conf currently provides:
// - listen 80
// - root /usr/share/nginx/html
// - SPA fallback: try_files $uri $uri/ /index.html
// - health endpoint: GET /health returns 200 OK

// Deployment expectation
// - docker buildx build --platform linux/arm64 ... works without changing the Dockerfile
// - No real .env file is copied into the image context
